var selectedExampleId = '';

function cloneEditorConfig(config) {
  return config ? JSON.parse(JSON.stringify(config)) : {};
}

function findEditorExample(id) {
  for (var i = 0; i < EDITOR_EXAMPLES.length; i++) {
    if (EDITOR_EXAMPLES[i].id === id) return EDITOR_EXAMPLES[i];
  }
  return null;
}

function exampleGroups() {
  var groups = [];
  var groupMap = {};
  EDITOR_EXAMPLES.forEach(function(example) {
    var category = example.category || 'Examples';
    if (!groupMap[category]) {
      groupMap[category] = { category: category, examples: [] };
      groups.push(groupMap[category]);
    }
    groupMap[category].examples.push(example);
  });
  return groups;
}

function exampleGlyph(example) {
  var type = example.diagramType || 'Example';
  var glyphs = {
    Flowchart: 'F',
    State: 'S',
    Architecture: 'A',
    Sequence: 'Q',
    Class: 'C',
    ER: 'ER',
    Timeline: 'T',
    Journey: 'J',
    'XY Chart': 'XY',
    Pie: 'P',
    Quadrant: '4Q',
    Gantt: 'G',
  };
  return glyphs[type] || type.slice(0, 2).toUpperCase();
}

function renderExamplePaletteHtml() {
  var examplesHtml = exampleGroups().map(function(group) {
    return '<section class="example-category">'
      + '<div class="example-category-title">' + escHtml(group.category) + '</div>'
      + '<div class="example-category-grid">'
      + group.examples.map(function(example) {
        return '<button class="example-dropdown-item" type="button" role="menuitem" data-example="' + escAttr(example.id) + '" data-diagram="' + escAttr(example.diagramType || '') + '" title="' + escAttr(example.description || example.label) + '">'
          + '<span class="example-item-title"><span class="example-item-glyph" aria-hidden="true">' + escHtml(exampleGlyph(example)) + '</span>' + escHtml(example.label) + '</span>'
          + '<span class="example-item-description">' + escHtml(example.description || '') + '</span>'
          + '</button>';
      }).join('')
      + '</div>'
      + '</section>';
  }).join('');

  return examplesHtml
    + '<div class="example-menu-footer">'
    + '<button class="example-clear-btn" type="button" data-action="clear-editor">New blank diagram</button>'
    + '</div>';
}

function renderExamplePalettes() {
  if (examplesSidebarList) examplesSidebarList.innerHTML = renderExamplePaletteHtml();
}

function markActiveExample(id) {
  selectedExampleId = id || '';
  document.querySelectorAll('.example-dropdown-item').forEach(function(item) {
    item.classList.toggle('active', item.dataset.example === selectedExampleId);
  });
}

function loadEditorExample(id) {
  var example = findEditorExample(id);
  if (!example) return;

  editor.value = example.source.trim();
  state.config = cloneEditorConfig(example.options);
  markActiveExample(example.id);

  // Examples are source/config presets only; keep the user's selected theme.
  if (typeof applyThemeToPage === 'function') applyThemeToPage(state.theme);
  if (typeof updateThemeButton === 'function') updateThemeButton();

  updateLineNumbers();
  updateCursorPos();
  scheduleRender(0);
  updateHash();
  showToast('Loaded ' + example.label);
}

var examplesSidebar = document.getElementById('examples-sidebar');
var examplesSidebarBtn = document.getElementById('examples-sidebar-btn');
var examplesSidebarClose = document.getElementById('examples-sidebar-close');
var examplesSidebarList = document.getElementById('examples-sidebar-list');

function positionExamplesSidebar() {
  if (!examplesSidebar || !examplesSidebarBtn) return;
  var rect = examplesSidebarBtn.getBoundingClientRect();
  var gutter = 12;
  var preferred = 360;
  var width = Math.min(preferred, window.innerWidth - gutter * 2);
  var left = Math.min(Math.max(gutter, rect.left), window.innerWidth - width - gutter);
  var top = rect.bottom + 8;
  var maxHeight = Math.max(260, window.innerHeight - top - gutter);
  examplesSidebar.style.setProperty('--examples-left', Math.round(left) + 'px');
  examplesSidebar.style.setProperty('--examples-top', Math.round(top) + 'px');
  examplesSidebar.style.setProperty('--examples-width', Math.round(width) + 'px');
  examplesSidebar.style.setProperty('--examples-max-height', Math.round(maxHeight) + 'px');
}

var examplesPopup = typeof createPopupController === 'function' ? createPopupController({
  popup: examplesSidebar,
  trigger: examplesSidebarBtn,
  visibility: { manageTabStops: true, toggleTriggerClass: false },
  beforeOpen: positionExamplesSidebar,
  afterOpen: function(meta) {
    if (examplesSidebarBtn) {
      examplesSidebarBtn.classList.add('active');
      examplesSidebarBtn.setAttribute('aria-pressed', 'true');
    }
    if (meta && meta.focusFirst && examplesSidebarList) {
      var activeItem = examplesSidebarList.querySelector('.example-dropdown-item.active') || examplesSidebarList.querySelector('.example-dropdown-item');
      if (activeItem) activeItem.focus({ preventScroll: false });
    }
  },
  afterClose: function() {
    if (examplesSidebarBtn) {
      examplesSidebarBtn.classList.remove('active');
      examplesSidebarBtn.setAttribute('aria-pressed', 'false');
    }
  },
  contains: function(target) {
    return !!(target.closest('#examples-sidebar') || target.closest('#examples-sidebar-btn'));
  },
  repositionOnResize: true,
  position: positionExamplesSidebar,
}) : { setOpen: function() {} };

function setExamplesSidebarOpen(open, meta) {
  examplesPopup.setOpen(open, meta || {});
}

function openExamplesSidebar() {
  setExamplesSidebarOpen(true, { focusFirst: true });
}

renderExamplePalettes();
setExamplesSidebarOpen(false);

if (examplesSidebarClose) {
  examplesSidebarClose.addEventListener('click', function() {
    setExamplesSidebarOpen(false, { restoreFocus: true });
  });
}

if (examplesSidebarList) {
  examplesSidebarList.addEventListener('click', function(e) {
    var item = e.target.closest('.example-dropdown-item');
    if (!item) return;
    loadEditorExample(item.dataset.example || '');
    setExamplesSidebarOpen(false);
  });
}

document.addEventListener('click', function(e) {
  var starter = e.target.closest('.placeholder-chip[data-example]');
  if (starter) {
    loadEditorExample(starter.dataset.example || '');
    return;
  }
  if (e.target.closest('[data-action="load-example"]')) {
    openExamplesSidebar();
    return;
  }
});


var cfgColors = { bg: '', fg: '', accent: '', line: '', muted: '', surface: '' };
var cfgFont = '';
var cfgPadding = 24;

var COLOR_PRESETS = [
  '#ffffff','#f5f5f5','#e0e0e0','#bdbdbd','#9e9e9e','#757575','#424242','#212121','#000000',
  '#f44336','#e91e63','#ff4081','#ff1744','#d50000',
  '#9c27b0','#673ab7','#3f51b5','#7c4dff','#aa00ff',
  '#2196f3','#03a9f4','#00bcd4','#1565c0','#2979ff','#0091ea',
  '#4caf50','#8bc34a','#009688','#00e676','#1b5e20',
  '#ffeb3b','#ffc107','#ff9800','#ff5722','#ff6d00',
  '#0f1117','#161b22','#1c2128','#0d1117','#1a1a2e','#16213e',
];

function readConfig() {
  var cfg = {};
  if (cfgColors.bg)      cfg.bg      = cfgColors.bg;
  if (cfgColors.fg)      cfg.fg      = cfgColors.fg;
  if (cfgColors.accent)  cfg.accent  = cfgColors.accent;
  if (cfgColors.line)    cfg.line    = cfgColors.line;
  if (cfgColors.muted)   cfg.muted   = cfgColors.muted;
  if (cfgColors.surface) cfg.surface = cfgColors.surface;
  if (cfgFont)           cfg.font    = cfgFont;
  if (cfgPadding !== 24) cfg.padding = cfgPadding;
  state.config = cfg;
}

var THEME_COLOR_MAP = { bg: 'bg', fg: 'fg', accent: 'accent', line: 'line', muted: 'muted', surface: 'surface' };

function getThemeColor(key) {
  if (!state.theme || !THEMES[state.theme]) return null;
  return THEMES[state.theme][THEME_COLOR_MAP[key]] || null;
}

function updateColorUI(key) {
  var override = cfgColors[key];
  var themeVal = getThemeColor(key);
  var effective = override || themeVal;
  var label  = document.getElementById('cfg-' + key + '-label');
  var swatch = document.getElementById('cfg-' + key + '-swatch');
  var btn    = document.querySelector('.color-edit-btn[data-cfg="' + key + '"]');

  if (label) {
    label.textContent = override || (themeVal ? themeVal : '–');
    label.style.opacity = override ? '1' : '0.45';
  }
  if (swatch) {
    swatch.style.background = effective || 'transparent';
    swatch.style.border = effective ? '1px solid rgba(0,0,0,0.15)' : '1px dashed var(--fg3)';
    swatch.style.opacity = override ? '1' : (themeVal ? '0.6' : '1');
  }
  if (btn) {
    var labelText = key.charAt(0).toUpperCase() + key.slice(1);
    btn.title = override ? 'Override: ' + override : (themeVal ? 'Theme default: ' + themeVal : 'Not set');
    btn.setAttribute('aria-label', 'Edit ' + labelText + ' color' + (effective ? ': ' + effective : ''));
  }
}

function refreshAllColorUIs() {
  Object.keys(cfgColors).forEach(function(k) { updateColorUI(k); });
}

refreshAllColorUIs();

var cfgEdgeStroke = 1;
var cfgNodeStroke = 1;

function applyStrokeOverrides(svgEl) {
  if (!svgEl) return;
  var defsEl = svgEl.querySelector('defs');

  function inDefs(el) {
    return defsEl && defsEl.contains(el);
  }

  if (cfgEdgeStroke !== 1) {
    var ew = String(cfgEdgeStroke);
    svgEl.querySelectorAll('line, path[fill="none"], polyline[fill="none"]').forEach(function(el) {
      if (!inDefs(el)) el.setAttribute('stroke-width', ew);
    });
    var arrowFactor = Math.sqrt(cfgEdgeStroke);
    svgEl.querySelectorAll('defs marker').forEach(function(marker) {
      var origW = parseFloat(marker.getAttribute('markerWidth')  || '8');
      var origH = parseFloat(marker.getAttribute('markerHeight') || '5');
      marker.setAttribute('viewBox', '0 0 ' + origW + ' ' + origH);
      marker.setAttribute('markerUnits', 'userSpaceOnUse');
      marker.setAttribute('markerWidth',  String(origW * arrowFactor));
      marker.setAttribute('markerHeight', String(origH * arrowFactor));
    });
  }

  if (cfgNodeStroke !== 1) {
    var nw = String(cfgNodeStroke);
    svgEl.querySelectorAll('rect, ellipse, circle, polygon').forEach(function(el) {
      if (!inDefs(el)) el.setAttribute('stroke-width', nw);
    });
  }
}

function makeStrokeSetter(numEl, sliderEl, getVal, setVal) {
  return function(raw) {
    var v = Math.max(0.25, Math.min(6, parseFloat(raw) || 1));
    v = Math.round(v * 4) / 4;
    setVal(v);
    numEl.value    = v;
    sliderEl.value = v;
    var svgEl = previewInner.querySelector('svg');
    if (svgEl) applyStrokeOverrides(svgEl);
  };
}

var edgeStrokeNum    = document.getElementById('cfg-edge-stroke');
var edgeStrokeSlider = document.getElementById('cfg-edge-stroke-slider');
var nodeStrokeNum    = document.getElementById('cfg-node-stroke');
var nodeStrokeSlider = document.getElementById('cfg-node-stroke-slider');

var setEdgeStroke = makeStrokeSetter(edgeStrokeNum, edgeStrokeSlider,
  function() { return cfgEdgeStroke; },
  function(v) { cfgEdgeStroke = v; }
);
var setNodeStroke = makeStrokeSetter(nodeStrokeNum, nodeStrokeSlider,
  function() { return cfgNodeStroke; },
  function(v) { cfgNodeStroke = v; }
);

edgeStrokeNum.addEventListener('input',    function() { setEdgeStroke(edgeStrokeNum.value); });
edgeStrokeSlider.addEventListener('input', function() { setEdgeStroke(edgeStrokeSlider.value); });
nodeStrokeNum.addEventListener('input',    function() { setNodeStroke(nodeStrokeNum.value); });
nodeStrokeSlider.addEventListener('input', function() { setNodeStroke(nodeStrokeSlider.value); });

// Clear every override (colors, font, padding, strokes) back to the active
// theme's defaults. setPadding / fontSelectLabel live in font-picker.js, which
// loads later but shares scope; this only runs on click, by which point they
// are defined.
function resetConfig() {
  Object.keys(cfgColors).forEach(function(k) { cfgColors[k] = ''; });
  cfgFont = '';
  if (typeof fontSelectLabel !== 'undefined' && fontSelectLabel) fontSelectLabel.textContent = 'Default';
  if (typeof setEdgeStroke === 'function') setEdgeStroke(1);
  if (typeof setNodeStroke === 'function') setNodeStroke(1);
  if (typeof setPadding === 'function') setPadding(24);
  refreshAllColorUIs();
  readConfig();
  if (typeof scheduleRender === 'function') scheduleRender(0);
  if (typeof showToast === 'function') showToast('Style reset to theme.');
}

var configResetBtn = document.getElementById('config-reset-btn');
if (configResetBtn) configResetBtn.addEventListener('click', resetConfig);

// Settings overlay: Source stays the left workspace; this slides the diagram
// settings over it, leaving the preview visible so changes show live. It is
// independent of the mobile Source/Preview switch.
var settingsBtn = document.getElementById('settings-btn');
var settingsCloseBtn = document.getElementById('settings-close-btn');
function setSettingsOpen(open) {
  if (!configView) return;
  configView.hidden = !open;
  configView.classList.toggle('visible', open);
  configView.setAttribute('aria-hidden', open ? 'false' : 'true');
  if (settingsBtn) {
    settingsBtn.classList.toggle('active', open);
    settingsBtn.setAttribute('aria-expanded', open ? 'true' : 'false');
    settingsBtn.setAttribute('aria-pressed', open ? 'true' : 'false');
  }
  if (open) {
    // On mobile the source panel may be hidden (Preview view); the settings
    // overlay lives over it, so bring it forward before showing them.
    if (typeof setMobilePanel === 'function') setMobilePanel('code');
    refreshAllColorUIs();
  }
}
if (settingsBtn) settingsBtn.addEventListener('click', function() { setSettingsOpen(configView.hidden); });
if (settingsCloseBtn) settingsCloseBtn.addEventListener('click', function() { setSettingsOpen(false); if (settingsBtn) settingsBtn.focus(); });
document.addEventListener('keydown', function(e) {
  if (e.key !== 'Escape' || !configView || configView.hidden) return;
  // A picker popup inside settings (font / colour) owns Escape while it is open,
  // so let it close and restore its own focus before settings reacts.
  if (document.querySelector('#font-popup:not([inert]), #color-popup:not([inert])')) return;
  setSettingsOpen(false);
  if (settingsBtn) settingsBtn.focus();
});


var colorPopup    = document.getElementById('color-popup');
var colorNative   = document.getElementById('color-native-input');
var colorHexInput = document.getElementById('color-hex-input');
var activeColorKey = null;
var activeColorAnchor = null;

var paletteEl = document.getElementById('color-palette');
COLOR_PRESETS.forEach(function(hex) {
  var btn = document.createElement('button');
  btn.className = 'color-swatch-btn';
  btn.style.background = hex;
  btn.title = hex;
  btn.setAttribute('aria-label', 'Use ' + hex);
  btn.addEventListener('click', function() {
    setActiveColor(hex);
  });
  paletteEl.appendChild(btn);
});

var colorPopupController = createPopupController({
  popup: colorPopup,
  trigger: function() { return activeColorAnchor; },
  triggerEvents: false,
  visibility: { focusSelector: '#color-hex-input' },
  beforeOpen: function() {
    positionAnchoredPopup(colorPopup, activeColorAnchor, { width: 240, height: 400 });
  },
  afterOpen: function() {
    document.querySelectorAll('.color-edit-btn').forEach(function(btn) { btn.setAttribute('aria-expanded', btn === activeColorAnchor ? 'true' : 'false'); });
    colorHexInput.select();
  },
  afterClose: function() {
    document.querySelectorAll('.color-edit-btn').forEach(function(btn) { btn.setAttribute('aria-expanded', 'false'); });
    activeColorKey = null;
    activeColorAnchor = null;
  },
  contains: function(target) {
    return !!(target.closest('#color-popup') || target.closest('.color-edit-btn'));
  },
  repositionOnResize: true,
  position: function() { positionAnchoredPopup(colorPopup, activeColorAnchor, { width: 240, height: 400 }); },
});

function openColorPopup(key, anchorEl) {
  activeColorKey = key;
  activeColorAnchor = anchorEl;
  var labels = { bg:'Background', fg:'Foreground', accent:'Accent', line:'Line', muted:'Muted', surface:'Surface' };
  document.getElementById('color-popup-title').textContent = labels[key] || key;

  var val = cfgColors[key] || '#ffffff';
  colorHexInput.value = cfgColors[key] || '';
  if (/^#[0-9a-fA-F]{6}$/.test(val)) colorNative.value = val;

  colorPopupController.open({ focusFirst: true });
}

function setActiveColor(hex) {
  if (!activeColorKey) return;
  cfgColors[activeColorKey] = hex;
  colorHexInput.value = hex;
  if (/^#[0-9a-fA-F]{6}$/.test(hex)) colorNative.value = hex;
  updateColorUI(activeColorKey);
  readConfig();
  scheduleRender(200);
}

function closeColorPopup(restoreFocus) {
  colorPopupController.close({ restoreFocus: !!restoreFocus });
}

document.querySelectorAll('.color-edit-btn').forEach(function(btn) {
  btn.addEventListener('click', function(e) {
    e.stopPropagation();
    var key = btn.dataset.cfg;
    if (colorPopup.classList.contains('open') && activeColorKey === key) {
      closeColorPopup(false); return;
    }
    openColorPopup(key, btn);
  });
});

document.getElementById('color-popup-close').addEventListener('click', function() { closeColorPopup(true); });

document.getElementById('color-clear-btn').addEventListener('click', function() {
  if (!activeColorKey) return;
  cfgColors[activeColorKey] = '';
  colorHexInput.value = '';
  updateColorUI(activeColorKey);
  readConfig();
  scheduleRender(200);
});

colorNative.addEventListener('input', function() {
  setActiveColor(colorNative.value);
});

colorHexInput.addEventListener('input', function() {
  var val = colorHexInput.value.trim();
  if (!val.startsWith('#')) val = '#' + val;
  if (/^#[0-9a-fA-F]{6}$/.test(val)) {
    colorNative.value = val;
    cfgColors[activeColorKey] = val;
    updateColorUI(activeColorKey);
    readConfig();
    scheduleRender(400);
  }
});


